     {
         if (!UnitPrefixes.TryGetValue(symbol, out var prefix))
         {
             return symbol.ToString();
         }

         return formats.HasFlag(MetricFormat.UseShortScale) ? prefix.ShortScaleWord : prefix.LongScaleWord;
     }
