/// <summary>
/// Replaces a metric prefix name with its corresponding symbol in the input string.
/// Uses O(1) dictionary lookup instead of iterating all prefixes.
/// </summary>
/// <param name="input">The string containing a metric prefix name.</param>
/// <returns>The string with the prefix name replaced by its symbol, or the original string if no match.</returns>
private static string ReplaceNameBySymbol(string input)
{
    foreach (var kvp in NameToSymbol)
    {
        var idx = input.IndexOf(kvp.Key, StringComparison.Ordinal);
        if (idx >= 0)
        {
            return string.Concat(input.AsSpan(0, idx), SymbolStrings[kvp.Value], input.AsSpan(idx + kvp.Key.Length));
        }
    }

    return input;
}

